class Solution:
    def equalFrequency(self, word):
        for i in range(len(word)):
            reduced = word[:i] + word[i + 1:]
            from collections import Counter
            counts = list(Counter(reduced).values())
            if len(set(counts)) == 1:
                return True
        return False

