class Solution:
    def equalFrequency(self, word):
        from collections import Counter
        freq = Counter(word)
        for ch in list(freq.keys()):
            freq[ch] -= 1
            vals = [v for v in freq.values() if v > 0]
            if len(set(vals)) <= 1:
                return True
            freq[ch] += 1
        return False

