var equalFrequency = function(word) {
    const freq = new Map();
    for (const c of word) freq.set(c, (freq.get(c) || 0) + 1);
    for (const ch of freq.keys()) {
        freq.set(ch, freq.get(ch) - 1);
        const vals = [...freq.values()].filter(v => v > 0);
        const ok = vals.every(v => v === vals[0]);
        if (ok) return true;
        freq.set(ch, freq.get(ch) + 1);
    }
    return false;
};
